const express = require('express');
const { Pool } = require('pg');
const Redis = require('ioredis');

const app = express();
app.use(express.json());

const pool = new Pool({
  host: process.env.DB_HOST || 'localhost',
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME || 'coupon_system',
  user: process.env.DB_USER || 'postgres',
  password: process.env.DB_PASSWORD || 'postgres',
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

const redis = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  retryStrategy: (times) => Math.min(times * 50, 2000),
});

async function initDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS coupons (
        id SERIAL PRIMARY KEY,
        code VARCHAR(50) UNIQUE NOT NULL,
        discount_type VARCHAR(20) NOT NULL,
        discount_value DECIMAL(10, 2) NOT NULL,
        max_uses INTEGER NOT NULL,
        current_uses INTEGER DEFAULT 0,
        valid_from TIMESTAMP NOT NULL,
        valid_until TIMESTAMP NOT NULL,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        CONSTRAINT check_uses CHECK (current_uses <= max_uses)
      );
      
      CREATE INDEX IF NOT EXISTS idx_coupon_code ON coupons(code);
      CREATE INDEX IF NOT EXISTS idx_coupon_validity ON coupons(valid_from, valid_until);
    `);

    await client.query(`
      CREATE TABLE IF NOT EXISTS coupon_redemptions (
        id SERIAL PRIMARY KEY,
        coupon_id INTEGER REFERENCES coupons(id),
        user_id VARCHAR(100) NOT NULL,
        order_id VARCHAR(100) UNIQUE NOT NULL,
        discount_amount DECIMAL(10, 2) NOT NULL,
        redeemed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        UNIQUE(coupon_id, user_id, order_id)
      );
      
      CREATE INDEX IF NOT EXISTS idx_redemption_user ON coupon_redemptions(user_id);
      CREATE INDEX IF NOT EXISTS idx_redemption_order ON coupon_redemptions(order_id);
    `);
  } finally {
    client.release();
  }
}

async function createCoupon(code, discountType, discountValue, maxUses, validFrom, validUntil) {
  const result = await pool.query(
    `INSERT INTO coupons (code, discount_type, discount_value, max_uses, valid_from, valid_until)
     VALUES ($1, $2, $3, $4, $5, $6)
     RETURNING *`,
    [code, discountType, discountValue, maxUses, validFrom, validUntil]
  );
  return result.rows[0];
}

function calculateDiscount(orderAmount, discountType, discountValue) {
  if (discountType === 'percentage') {
    return Math.min(orderAmount * (discountValue / 100), orderAmount);
  } else if (discountType === 'fixed') {
    return Math.min(discountValue, orderAmount);
  }
  return 0;
}

async function redeemCouponWithTransaction(userId, couponCode, orderId, orderAmount) {
  const client = await pool.connect();
  
  try {
    await client.query('BEGIN');
    
    const couponResult = await client.query(
      `SELECT * FROM coupons 
       WHERE code = $1 
       FOR UPDATE`,
      [couponCode]
    );

    if (couponResult.rows.length === 0) {
      throw new Error('COUPON_NOT_FOUND');
    }

    const coupon = couponResult.rows[0];
    const now = new Date();

    if (now < new Date(coupon.valid_from)) {
      throw new Error('COUPON_NOT_YET_VALID');
    }

    if (now > new Date(coupon.valid_until)) {
      throw new Error('COUPON_EXPIRED');
    }

    if (coupon.current_uses >= coupon.max_uses) {
      throw new Error('COUPON_FULLY_REDEEMED');
    }

    const existingRedemption = await client.query(
      `SELECT * FROM coupon_redemptions 
       WHERE order_id = $1`,
      [orderId]
    );

    if (existingRedemption.rows.length > 0) {
      throw new Error('ORDER_ALREADY_HAS_COUPON');
    }

    const discountAmount = calculateDiscount(orderAmount, coupon.discount_type, coupon.discount_value);

    await client.query(
      `UPDATE coupons 
       SET current_uses = current_uses + 1 
       WHERE id = $1`,
      [coupon.id]
    );

    await client.query(
      `INSERT INTO coupon_redemptions (coupon_id, user_id, order_id, discount_amount)
       VALUES ($1, $2, $3, $4)`,
      [coupon.id, userId, orderId, discountAmount]
    );

    await client.query('COMMIT');

    return {
      success: true,
      discountAmount,
      finalAmount: orderAmount - discountAmount,
      couponCode: coupon.code,
      discountType: coupon.discount_type,
      discountValue: coupon.discount_value
    };

  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
}

async function redeemCouponWithRedisLock(userId, couponCode, orderId, orderAmount) {
  const lockKey = `coupon_lock:${couponCode}`;
  const lockValue = `${userId}:${orderId}:${Date.now()}`;
  const lockTTL = 10;

  const acquired = await redis.set(lockKey, lockValue, 'EX', lockTTL, 'NX');
  
  if (!acquired) {
    throw new Error('COUPON_LOCKED_TRY_AGAIN');
  }

  try {
    const cacheKey = `coupon:${couponCode}`;
    let coupon = await redis.get(cacheKey);
    
    if (coupon) {
      coupon = JSON.parse(coupon);
    } else {
      const result = await pool.query(
        'SELECT * FROM coupons WHERE code = $1',
        [couponCode]
      );
      
      if (result.rows.length === 0) {
        throw new Error('COUPON_NOT_FOUND');
      }
      
      coupon = result.rows[0];
      await redis.setex(cacheKey, 300, JSON.stringify(coupon));
    }

    const now = new Date();
    if (now < new Date(coupon.valid_from)) {
      throw new Error('COUPON_NOT_YET_VALID');
    }
    if (now > new Date(coupon.valid_until)) {
      throw new Error('COUPON_EXPIRED');
    }

    const result = await redeemCouponWithTransaction(userId, couponCode, orderId, orderAmount);
    
    await redis.del(cacheKey);
    
    return result;

  } finally {
    const currentLock = await redis.get(lockKey);
    if (currentLock === lockValue) {
      await redis.del(lockKey);
    }
  }
}

async function redeemCouponOptimistic(userId, couponCode, orderId, orderAmount) {
  const maxRetries = 3;
  let attempt = 0;

  while (attempt < maxRetries) {
    const client = await pool.connect();
    
    try {
      await client.query('BEGIN');

      const couponResult = await client.query(
        `SELECT * FROM coupons WHERE code = $1`,
        [couponCode]
      );

      if (couponResult.rows.length === 0) {
        throw new Error('COUPON_NOT_FOUND');
      }

      const coupon = couponResult.rows[0];
      const now = new Date();

      if (now < new Date(coupon.valid_from)) {
        throw new Error('COUPON_NOT_YET_VALID');
      }

      if (now > new Date(coupon.valid_until)) {
        throw new Error('COUPON_EXPIRED');
      }

      if (coupon.current_uses >= coupon.max_uses) {
        throw new Error('COUPON_FULLY_REDEEMED');
      }

      const existingRedemption = await client.query(
        `SELECT * FROM coupon_redemptions WHERE order_id = $1`,
        [orderId]
      );

      if (existingRedemption.rows.length > 0) {
        throw new Error('ORDER_ALREADY_HAS_COUPON');
      }

      const discountAmount = calculateDiscount(orderAmount, coupon.discount_type, coupon.discount_value);

      const updateResult = await client.query(
        `UPDATE coupons 
         SET current_uses = current_uses + 1 
         WHERE id = $1 AND current_uses = $2 AND current_uses < max_uses
         RETURNING *`,
        [coupon.id, coupon.current_uses]
      );

      if (updateResult.rows.length === 0) {
        await client.query('ROLLBACK');
        attempt++;
        client.release();
        
        if (attempt >= maxRetries) {
          throw new Error('COUPON_REDEMPTION_CONFLICT');
        }
        
        await new Promise(resolve => setTimeout(resolve, Math.random() * 100));
        continue;
      }

      await client.query(
        `INSERT INTO coupon_redemptions (coupon_id, user_id, order_id, discount_amount)
         VALUES ($1, $2, $3, $4)`,
        [coupon.id, userId, orderId, discountAmount]
      );

      await client.query('COMMIT');
      client.release();

      return {
        success: true,
        discountAmount,
        finalAmount: orderAmount - discountAmount,
        couponCode: coupon.code,
        discountType: coupon.discount_type,
        discountValue: coupon.discount_value
      };

    } catch (error) {
      await client.query('ROLLBACK');
      client.release();
      
      if (error.message === 'COUPON_NOT_FOUND' || 
          error.message === 'COUPON_NOT_YET_VALID' ||
          error.message === 'COUPON_EXPIRED' ||
          error.message === 'COUPON_FULLY_REDEEMED' ||
          error.message === 'ORDER_ALREADY_HAS_COUPON') {
        throw error;
      }
      
      attempt++;
      if (attempt >= maxRetries) {
        throw error;
      }
      
      await new Promise(resolve => setTimeout(resolve, Math.random() * 100));
    }
  }
}

app.post('/api/coupons', async (req, res) => {
  try {
    const { code, discountType, discountValue, maxUses, validFrom, validUntil } = req.body;
    
    if (!code || !discountType || !discountValue || !maxUses || !validFrom || !validUntil) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    const coupon = await createCoupon(code, discountType, discountValue, maxUses, validFrom, validUntil);
    res.status(201).json(coupon);
  } catch (error) {
    if (error.code === '23505') {
      return res.status(409).json({ error: 'Coupon code already exists' });
    }
    res.status(500).json({ error: 'Failed to create coupon' });
  }
});

app.post('/api/redeem', async (req, res) => {
  try {
    const { userId, couponCode, orderId, orderAmount } = req.body;

    if (!userId || !couponCode || !orderId || !orderAmount) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    if (orderAmount <= 0) {
      return res.status(400).json({ error: 'Invalid order amount' });
    }

    const result = await redeemCouponWithTransaction(userId, couponCode, orderId, orderAmount);
    res.json(result);

  } catch (error) {
    const errorMessages = {
      'COUPON_NOT_FOUND': { status: 404, message: 'Coupon not found' },
      'COUPON_NOT_YET_VALID': { status: 400, message: 'Coupon is not yet valid' },
      'COUPON_EXPIRED': { status: 400, message: 'Coupon has expired' },
      'COUPON_FULLY_REDEEMED': { status: 400, message: 'Coupon has been fully redeemed' },
      'ORDER_ALREADY_HAS_COUPON': { status: 400, message: 'This order already has a coupon applied' },
      'COUPON_LOCKED_TRY_AGAIN': { status: 429, message: 'Coupon is being processed, please try again' },
      'COUPON_REDEMPTION_CONFLICT': { status: 409, message: 'Coupon redemption conflict, please try again' }
    };

    const errorInfo = errorMessages[error.message];
    if (errorInfo) {
      return res.status(errorInfo.status).json({ error: errorInfo.message });
    }

    console.error('Coupon redemption error:', error);
    res.status(500).json({ error: 'Failed to redeem coupon' });
  }
});

app.get('/api/coupons/:code', async (req, res) => {
  try {
    const { code } = req.params;
    
    const result = await pool.query(
      `SELECT code, discount_type, discount_value, max_uses, current_uses, 
              valid_from, valid_until 
       FROM coupons 
       WHERE code = $1`,
      [code]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Coupon not found' });
    }

    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch coupon' });
  }
});

app.get('/api/redemptions/:userId', async (req, res) => {
  try {
    const { userId } = req.params;
    
    const result = await pool.query(
      `SELECT r.*, c.code, c.discount_type, c.discount_value
       FROM coupon_redemptions r
       JOIN coupons c ON r.coupon_id = c.id
       WHERE r.user_id = $1
       ORDER BY r.redeemed_at DESC`,
      [userId]
    );

    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch redemptions' });
  }
});

